"""
Standalone patch — writes mkt-context for Isaiah 19-23 directly.
Run: python3 scripts/zc-context-isaiah-19-23-patch.py
Chapters: 19 (25v), 20 (6v), 21 (17v), 22 (25v), 23 (18v) = 91 verses
"""
import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

ISA_CONTEXT = {
  "19": {
    "1": "<p>Isaiah 19:1 opens the Egypt oracle with one of Isaiah's most vivid theophanies: 'the LORD is coming on a swift cloud to Egypt.' The cloud-chariot of YHWH is the divine warrior vehicle of Ps 68:4 ('extol him who rides on the clouds'), 104:3 ('he makes the clouds his chariot'), and Deut 33:26 ('who rides the heavens to help you'). The Egyptian theological system revolves around the sun-deity Ra riding his solar barque across the heavens — YHWH on his cloud-chariot directly confronts Egypt's theological claim. The idols of Egypt (elilim, worthless/nothings) tremble (va'nu, shake/quake) and 'Egypt's heart melts within it' (levav Mitsrayim yimmas beqirbo, the heart of Egypt will melt within itself) — the total terror-dissolution of Deut 20:8 ('the hearts of his comrades will melt like his') applied to Egypt itself. The Egyptian pantheon (Amun-Ra, Osiris, Isis, Horus, Ptah, Thoth) is personified in the idols that collapse before YHWH.</p>",
    "2": "<p>'I will stir up Egyptians against Egyptians, and they will fight each other — brother against brother, neighbor against neighbor, city against city, region against region' — the divine causation of Egypt's civil fragmentation. Egypt's history in the Late Period (8th-7th century BCE) is exactly this: the 24th Dynasty (Saite, under Tefnakht and Bakenranef) competed with the 25th Cushite Dynasty (Piankhi, Shabaka) for control of Egypt. After the Cushites were driven out by Assyria (671-664 BCE), the Delta lords fragmented further until Psamtik I (Necho's father) reunified Egypt in 656 BCE. The four levels of civil conflict: brother against brother (the family unit), neighbor against neighbor (the neighborhood), city against city (urban rivalry — Memphis vs. Thebes vs. Sais), region against region (Upper Egypt vs. Delta).</p>",
    "3": "<p>'Egypt's spirit will drain away within it; I will confound its plans; the Egyptians will turn to idols, enchanters, mediums, and spiritists' — the collapse of Egyptian governance and the resort to magic. Egypt's ruach (spirit/breath of governance) 'drains away' (vevaqqah, will become empty/poured out). The 'confounding of plans' (vebillaiti et-atsato, I will confuse its counsel) directly targets Egypt's famous wisdom tradition — the royal court's sages who advised pharaoh. In crisis the Egyptians turn to: elilim (idols/worthless ones), haittim (the ones who murmur/the enchanters), haoboth (the ob spirits/mediums), yiddeoni (the knowing-ones/spiritists). Isaiah 8:19 condemns the same resort to mediums and spiritists in Judah: 'Should not a people inquire of their God?' The resort to the spirit-world is the failure of official wisdom acknowledged.</p>",
    "4": "<p>'I will hand Egypt over to a harsh master; a cruel king will rule over them, declares the Lord, the LORD of hosts' — the political consequence: YHWH delivers (sakarti, I will shut up/deliver) Egypt into the hand of 'adon qasheh' (a hard/harsh master) and a 'melech az' (fierce/cruel king) will rule them. The historical candidates: Assyrian domination (Esarhaddon conquered Egypt in 671 BCE, Ashurbanipal destroyed Thebes/No-Amon in 663 BCE — Nah 3:8 refers to this); Babylonian campaigns of Nebuchadnezzar against Egypt (604, 601, and 568 BCE); or Persian domination under Cambyses II (who conquered Egypt in 525 BCE and ruled it harshly — killing the sacred Apis bull, according to Herodotus). The 'declares the LORD of hosts' closing is the divine authentication signature.</p>",
    "5": "<p>'The water of the Nile will dry up, and the river will be parched and drained' — the ecological judgment on Egypt's foundational resource. Egypt was entirely dependent on the Nile's annual flood for agriculture — without it, Egypt was desert. 'The waters will fail from the sea' (veneharoth yehalu veyaveshu, the waters from the sea will fail and dry up) — the Nile called 'the sea' (yam) because of its Delta expanse. The drying of the Nile is the anti-Exodus miracle: just as YHWH split the Reed Sea to deliver Israel from Egypt, he now drains Egypt's lifeblood. The Egyptian Nile-god Hapi personified the flood's abundance — its absence = Hapi's defeat. Ezek 29:3-5 uses similar imagery (Pharaoh as a great dragon in the Nile, dragged out and dried).</p>",
    "6": "<p>'The channels will become foul; the branches of Egypt's Nile will shrink and dry up; reeds and rushes will wither' — the Delta's network of waterways (ye'orei Mitsrayim, the canals of Egypt) become foul (vane'azeru vemaqu ye'ore mitsrayim, will become noxious and the canals of Egypt will sink and dry). The Delta was a maze of Nile branches and artificial canals that supported dense agricultural settlement. Without the annual Nile flood, these canals stagnated, silted, and collapsed. The reeds (qaneh) and rushes (suf, the same word as 'Red Sea' = Yam Suph = Reed Sea) withering — the papyrus-marsh ecology of the Delta that supported Egypt's entire papyrus industry (writing materials, boats, baskets) collapsing.</p>",
    "7": "<p>'The papyrus reeds along the Nile, at its outflows, and all crops planted along its banks will wither, blow away, and cease to exist' — the comprehensive agricultural failure: 'eroth al-yeor, al-pi yeor' (meadows by the Nile, by the mouth of the Nile) — the delta outflow areas. All crops (kol mizra yeor, every planting of the Nile) will dry up (yibash, become dry), 'driven away and cease to exist' (nidaf velo haya, driven away and will not be). Egypt's Mediterranean role as the ancient world's granary (the source of grain for Rome in the imperial period) is anticipated in reverse: the grain-producer becomes a famine zone. The Romans actually depended on Egyptian grain to feed Rome — the prophetic reversal of Egypt's agricultural power is geopolitically significant.</p>",
    "8": "<p>'The fishermen will mourn; all who cast a hook into the Nile will lament; those who spread nets on the water will languish' — the fishing industry's collapse. Egypt's Nile fishery was one of the great food sources of the ancient world — Egyptian reliefs and texts describe elaborate fishing operations using hooks, nets, and spears. 'The fishermen will mourn' (ve'anhu hadayigim, the fishermen will groan) and 'those who cast a hook' (kol-sholikei chakkah, all who throw the hook). The three fishing methods: hook (chakkah), net (mikmoreth), drag-net (cherem). The drying of the Nile eliminates fish habitats — without water, no fish; without fish, the entire protein supply of Lower Egypt collapses. The fishing industry was one of Egypt's major economic sectors, supporting thousands of workers.</p>",
    "9": "<p>'Those who work with combed flax and those who weave fine linen will be put to shame' — the linen/flax industry's collapse. Egypt was the ancient world's premier linen producer — Egyptian linen (bussos, fine linen) was a luxury export commodity throughout the Mediterranean. 'Those who work with combed flax' (ovdei fishtim serikot, those who work with the combed flax) and weavers of fine cloth (veoregei churim, weavers of white/fine fabric) 'will be put to shame' (vehobishu). Egyptian linen production required extensive Nile flood water for soaking and retting the flax fibers — without Nile water, the entire textile production chain collapses. The shame is economic: the skilled workers who defined Egypt's luxury export sector are reduced to nothing.</p>",
    "10": "<p>'Egypt's foundations will be crushed; all who work for hire will be sick at heart' — 'shataot' (her foundations, the pillars/supports of society) 'will be crushed' (daku, pounded to pieces). The 'foundations' of Egypt = the economic infrastructure on which society rests: the Nile-dependent agriculture, fishing, textile, and trade industries. 'All who work for hire will be sick at heart' (kol-osei seker agmei nafesh, all who make wages will be grieved in soul). The hired workers (sakir, day laborers who work for wages) represent the entire dependent labor force — without the Nile industries, the entire wage economy of Egypt collapses. The 'sick at heart' (agmei nefesh, sorrowful of soul) describes total psychological devastation accompanying economic ruin.</p>",
    "11": "<p>'The princes of Zoan are utter fools; the wisest of Pharaoh's counselors give worthless advice. How can they say to Pharaoh, I am a descendant of the sages, a son of ancient kings?' — the confounding of Egypt's wisdom elite. Zoan (Tanis, in the eastern Delta, the royal capital of the 21st and 22nd Dynasties) was the political nerve center. 'The princes of Zoan are complete fools' (ach evvil sarei Tso'an, utterly foolish are the princes of Zoan). Egypt's wisdom tradition was one of the ancient world's greatest — Proverbs 22:17-24:22 shows direct influence from the Egyptian Wisdom of Amenemope. The counselors who claim descent from 'sages' (chachamim, wise men) and 'kings of antiquity' (malkei qedem, ancient kings) are precisely those whose wisdom YHWH confounds. The boast of ancient lineage as qualification for wisdom is destroyed when the counsel fails.</p>",
    "12": "<p>'Where are your wise men now? Let them tell you; let them make known what the LORD of hosts has planned against Egypt' — the prophetic challenge to Egyptian wisdom: 'ayam eifoh chakhamekha, where then are your wise men?' The challenge to wisdom is: can they declare (veyagidu, and let them tell you) what YHWH has purposed (ya'ats, planned/counseled) against Egypt? The test of wisdom is precisely the knowledge of what YHWH has planned — and the Egyptian sages, for all their astronomical and medical knowledge, cannot access divine counsel because they do not know YHWH. 1 Cor 1:20 ('Where is the wise person? Where is the teacher of the law? Where is the philosopher of this age? Has not God made foolish the wisdom of the world?') echoes this passage.</p>",
    "13": "<p>'The princes of Zoan have made themselves fools; the princes of Memphis are deluded; the leaders of Egypt's clans have led the nation astray' — the double accusation against both royal capitals: Zoan (Tanis, the Delta political capital) and Noph (Memphis, the ancient administrative capital, site of the great Ptah temple). The leaders have 'deceived themselves' (nisha'u, they are deceived/seduced) and the leaders of the tribal subdivisions (pinnot shevateiha, the corner-stones of her tribes) have 'led Egypt astray' (hitu et-Mitsrayim, they caused Egypt to err/wander). The corner-stone imagery for tribal leaders is interesting: the cornerstones support the structure — when they lead astray, the entire building collapses. Isaiah 28:16 uses cornerstone imagery for the Messianic foundation stone.</p>",
    "14": "<p>'The LORD has poured into Egypt a spirit of confusion; the Egyptians err in everything they do, like a drunkard reeling in his vomit' — the divine causation of the confusion: 'YHWH masakh beqirba ruach iveim, YHWH has mixed/blended within her a spirit of distortions/perversions.' The ruach ivim (spirit of perversions, from ivah = twist/pervert) is poured as a judge pours a mixed wine (masakh = to mix a drink). The result: the Egyptians 'err in all their work' (hita Mitsrayim bekhol-ma'aseh, Egypt errs/staggers in all its work) 'like a drunk staggering in his vomit' (keasher yit'eh hashikkor beqiu, as the drunk staggers in his vomit). The vivid image of incompetent governance as drunken reeling echoes the priestly and prophetic drunkenness of 28:7-8 where priests and prophets 'reel with wine and stagger from beer.'</p>",
    "15": "<p>'There will be nothing Egypt can accomplish — neither head nor tail, neither palm branch nor reed' — the comprehensive social dysfunction: 'velo-yihyeh leMitsrayim ma'aseh, there will be no work/deed for Egypt.' The 'head and tail, palm branch and reed' formula of 9:14-15 (where Isaiah identified head = honored elder, tail = lying prophet) is here applied to Egypt: the entire social spectrum from top to bottom is dysfunctional. Egypt, which was the most administratively organized society of the ancient world (its tax records, census data, and engineering feats were unparalleled), is reduced to total incompetence.</p>",
    "16": "<p>'In that day the Egyptians will be like frightened women, trembling with fear because of the hand of the LORD of hosts that he raises against them' — the first of the seven 'In that day' oracles (vv.16-25) that transform the Egypt judgment into eschatological promise. The first movement: Egypt as terrified women (kenashim, like women = using femininity as a fear metaphor in patriarchal culture, cf. Nah 3:13). The 'hand of YHWH raised against them' (tenufat yad Yhwh tseva'ot, the wave-offering of the hand of YHWH of hosts) — the same 'raised hand' of judgment from the four-stanza cycle (9:12, 17, 21; 10:4), now applied to Egypt. The irony: Egypt that once raised its hand against Israel in slavery now trembles at YHWH's raised hand.</p>",
    "17": "<p>'The land of Judah will become a source of dread to Egypt; whenever Judah is mentioned, they will tremble because of what the LORD of hosts has determined against Egypt' — the reversal of Exod 15:14-16: in the Song of the Sea, the nations tremble at YHWH's victory. Now specifically 'the land of Judah will be a terror to Egypt' (vehayetah admat Yehudah leMitsrayim lachagga, the land of Judah will be to Egypt a dread). Egypt, which had subjugated Israel, will fear even the mention of Judah. The historical context: after Sennacherib's defeat at Jerusalem (701 BCE), Egypt would have reason to fear the God of Jerusalem. The second fulfillment: Alexander the Great conquering Egypt in 332 BCE without resistance — the Persian satrap surrendered immediately — happened after Alexander defeated the Persians at Issus.</p>",
    "18": "<p>'In that day five cities in Egypt will speak the language of Canaan and swear loyalty to the LORD of hosts. One will be called the City of the Sun' — the second eschatological oracle: Egyptian cities adopting Hebrew/Canaanite and swearing allegiance (nishba, taking an oath) to YHWH. 'Five cities' = a representative number (not necessarily exactly five). 'The language of Canaan' (sefat Kena'an, the lip of Canaan = the Hebrew/Aramaic language family) = conversion expressed through adopting the language of YHWH's covenant community. The 'City of the Sun' (ir haheres, city of the sun/destruction — a textual variant haheres vs. hahedeg vs. hatsedeq = city of destruction vs. city of righteousness) is probably Heliopolis (Greek: On, Hebrew: Aven), the great sun-worship center near Cairo. The Jewish temple at Leontopolis (built c. 160 BCE) partially fulfilled this oracle.</p>",
    "19": "<p>'In that day there will be an altar to the LORD in the heart of Egypt, and a standing stone at its border dedicated to the LORD' — the third eschatological oracle: cultic YHWH-worship infrastructure in Egypt. An 'altar to YHWH' (mizbeach laYHWH) in the middle of the land of Egypt (betokh erets Mitsrayim) and a matzevah (standing stone/pillar) at its border dedicated to YHWH. The matzevah (standing stone) was the original marker of covenant between persons or between man and God (Gen 28:18, Jacob at Bethel; 31:45, Jacob and Laban; Exod 24:4, Moses at Sinai). While the matzevah was later prohibited (Deut 16:22: 'Do not erect a matzevah, for YHWH your God hates them'), here YHWH himself establishes one as the border-marker of Egypt's covenant allegiance. The Elephantine Jewish colony (5th century BCE) had a YHWH temple in Upper Egypt, providing historical resonance.</p>",
    "20": "<p>'It will serve as a sign and witness to the LORD of hosts in the land of Egypt. When they cry out to the LORD because of their oppressors, he will send them a savior and champion who will rescue them' — the covenant-witness formula applied to Egypt. The altar and standing stone become 'an ot ule'ed laYHWH tseva'ot be'erets Mitsrayim, a sign and witness to YHWH of hosts in Egypt.' The most remarkable element: 'when they cry out to the LORD because of their oppressors, he will send them a savior and champion who will rescue them' (yishla lahem moshia verav vehitsila, he will send to them a savior and great one/defender who will deliver). The moshia (savior/deliverer) language is the Exodus vocabulary — Moses as deliverer from oppression. YHWH responding to Egypt's cry to him with a deliverer applies the foundational Israel-story to Egypt. This is one of the OT's most astonishing universalizations.</p>",
    "21": "<p>'The LORD will make himself known to Egypt, and the Egyptians will acknowledge the LORD in that day. They will worship him with sacrifices and grain offerings; they will make vows to the LORD and keep them' — the conversion of Egypt: YHWH 'making himself known' (veyoda YHWH et-Mitsrayim, and YHWH will be known to Egypt) and Egypt 'acknowledging YHWH' (veyede Mitsrayim et-YHWH, Egypt will know YHWH). The 'know' (yada) is the covenant-knowledge of relationship, not merely intellectual information. The worship that follows: sacrifices (zevach, slaughter-sacrifices), grain offerings (minchah), vows (nedarim) kept (shillemu, fulfilled). These are the three components of the complete Israelite worship system, now adopted by Egypt. The pattern: YHWH strikes → Egypt knows YHWH → Egypt worships YHWH. Egypt learning through judgment what Israel should have learned.</p>",
    "22": "<p>'The LORD will strike Egypt — striking and healing — and they will turn back to the LORD. He will hear their pleas and heal them' — the 'striking and healing' (nakoh vechafo, smiting and healing) formula is theologically dense. YHWH who struck Egypt with the ten plagues (Exod 7-12) now strikes Egypt again — but the purpose is healing (rapa), not destruction. The verb nakoh vechafo (he will smite and he will heal) appears also in Deut 32:39 ('I wound and I heal; there is no one who can deliver from my hand') and Hos 6:1 ('He has torn us to pieces but he will heal us; he has injured us but he will bind up our wounds'). Egypt's response: 'they will return to YHWH' (shavu ad-YHWH, they will turn/return to YHWH) — the shuv (repentance) language of the prophets applied to Egypt. YHWH 'hearing their supplications' (veishma el-techinnotheyhem, and he will hear their pleas) and healing them — Egypt receiving the covenant mercy normally reserved for Israel.</p>",
    "23": "<p>'In that day there will be a highway from Egypt to Assyria. The Assyrians will come into Egypt and the Egyptians into Assyria, and the Egyptians will worship together with the Assyrians' — the eschatological highway connecting the two great empires of Isaiah's world. The 'highway' (mesillah, a raised/built road) from Egypt to Assyria passing through Israel — the great Via Maris (the coastal road connecting Egypt and Mesopotamia through Canaan). In the new age, this road becomes a route of worship rather than military advance. 'The Egyptians will worship with the Assyrians' (ve'avdu Ashur et-Mitsrayim, the Assyrians will worship with Egypt) — the two greatest military powers of the ancient Near East, traditional enemies, worshiping YHWH together. This is the eschatological fulfillment of the nations' pilgrimage to Zion (2:2-4; Mic 4:1-4).</p>",
    "24": "<p>'In that day Israel will be the third alongside Egypt and Assyria, a blessing in the midst of the earth' — the geopolitical reconfiguration: Israel as 'the third' (shelishi, the third one) in a three-nation coalition with Egypt and Assyria. 'A blessing in the midst of the earth' (berachah beqerev ha'arets, a blessing in the middle of the land) — Israel as the conduit of blessing to the nations, fulfilling the Abrahamic promise of Gen 12:3 ('all peoples on earth will be blessed through you'). The geographical 'in the midst of the earth' — Israel sits geographically between Egypt (southwest) and Assyria/Mesopotamia (northeast), the land bridge between Africa and Asia. The historical reality of Israel's geographic position as crossroads becomes the theological reality of Israel as mediating blessing between the nations.</p>",
    "25": "<p>'Whom the LORD of hosts will bless, saying, Blessed be Egypt my people, and Assyria the work of my hands, and Israel my inheritance' — the most astonishing verse in the Egypt oracle, perhaps in all of Isaiah. YHWH applies his three covenantal designations to the three nations: Egypt receives 'ammi' (my people — the title reserved exclusively for Israel in Exod 3:7, 6:7; Hos 1:9-2:23; Jer 31:33); Assyria receives 'ma'aseh yadai' (the work of my hands — applied to Israel in 29:23; 45:11; 60:21; 64:8); Israel receives 'nachalati' (my inheritance — Israel's own self-designation, Ps 28:9; 78:71). The boundary-crossing is complete: the language of exclusive covenantal relationship extended to former enemies. Paul cites Hos 1-2 in Rom 9:25-26 to argue the same point about Gentile inclusion. This verse is the OT's clearest proto-universalist prophetic statement.</p>"
  },
  "20": {
    "1": "<p>Isaiah 20:1 provides the historical anchor for this chapter: 'In the year that the tartan came to Ashdod, when Sargon king of Assyria sent him.' The tartan (turtanu in Akkadian) was the second-in-command of the Assyrian army, the supreme commander second only to the king. Sargon II (722-705 BCE) is the Assyrian king who captured Samaria (722 BCE) and reorganized the empire after Tiglath-Pileser III and Shalmaneser V. The Ashdod revolt (714-711 BCE): Ashdod (Philistine coastal city) revolted against Assyria, possibly with Egyptian encouragement and backing. The Assyrian annals of Sargon II record the capture of Ashdod and the installation of a new governor. The revolt was supported by the promise of Egyptian military aid — aid that never materialized. This is the specific diplomatic situation Isaiah's sign-act addresses.</p>",
    "2": "<p>'At that time the LORD spoke through Isaiah son of Amoz, saying, Go, take the sackcloth off your waist and remove the sandal from your foot. He obeyed, walking naked and barefoot' — the sign-act (mofet, portent). The sackcloth (saq) was the prophet's distinctive garment (1 Kgs 21:27; 2 Kgs 1:8; Zech 13:4) — possibly Isaiah had been wearing it as a sign of mourning over the coming judgment. The command: remove sackcloth and sandals and walk naked (arom, naked/uncovered) and barefoot (yachef, unshod). Isaiah walked this way for three years — a three-year living prophecy acted out in the streets of Jerusalem. The nakedness signifies: captive status (prisoners were stripped in Assyrian deportations), poverty, and shame. The sandal-removal signifies: captive status (free people wore sandals; slaves and prisoners went barefoot).</p>",
    "3": "<p>'Then the LORD said, Just as my servant Isaiah has walked naked and barefoot for three years as a sign and portent against Egypt and Cush' — YHWH's interpretation of the sign-act: 'ka'asher halakh avdi Yeshayahu arom veyachef shalosch shanim ot umofet al-Mitsrayim ve'al-Kush, as my servant Isaiah has walked naked and barefoot three years as a sign and wonder against Egypt and against Cush.' The 'sign and portent' (ot umofet) language is the Exodus vocabulary — Exod 7:3 ('I will multiply my signs and wonders in Egypt'); Deut 6:22 ('YHWH showed signs and wonders against Egypt'). Isaiah is here a living Exodus-type sign: as Moses's signs pointed to Egypt's judgment, Isaiah's naked walk points to Egypt's humiliation.</p>",
    "4": "<p>'So the king of Assyria will lead away the Egyptian captives and the Cushite exiles, young and old alike, naked and barefoot, with their buttocks exposed — Egypt's humiliation laid bare' — the sign's meaning: the Assyrian king leading away Egyptian and Cushite captives (shevi Mitsrayim vegolat Kush, the captivity of Egypt and the exile of Cush). The specific detail: 'young and old, naked and barefoot, with their buttocks exposed' (galui sheth, the buttocks uncovered — the ultimate exposure of shame). Assyrian reliefs from Nineveh and other sites show exactly this: captive populations stripped and marched, sometimes with deliberate exposure of genitalia as an act of degradation. The Cushite pharaohs (25th Dynasty) who seemed the great hope for resistance against Assyria will themselves be stripped and marched. This was partly fulfilled when Esarhaddon conquered Egypt in 671 BCE and Ashurbanipal destroyed Thebes in 663 BCE.</p>",
    "5": "<p>'Those who looked to Cush with expectation and took pride in Egypt will be terrified and put to shame' — the political application to Judah: those who 'looked to Cush with expectation' (vehayu chettim min-Kush, and they will be terrified from Cush = will be terrified about Cush) and those who 'took pride in Egypt' (ufeerim me'Mitsrayim, boasted about Egypt). The political faction in Jerusalem (court officials, merchants, landowners) who wanted to join an anti-Assyrian coalition with Egypt will be 'terrified and ashamed' (vebaioshu, and will be put to shame) when their hoped-for ally is humiliated. 2 Kgs 18:19-21 records Rabshakeh's taunt: 'What confidence is this you have? Do you think I am only saying empty words? Look now, you are depending on Egypt, that broken reed of a staff, which pierces the hand of the man who leans on it!'</p>",
    "6": "<p>'In that day the people of this coastland will say, This is what has happened to those we relied on, to whom we fled for help and rescue from the king of Assyria. How then shall we escape?' — the conclusion drawn by 'the people of this coastland' (yoshev haiy hazeh, the inhabitants of this coastland — the Philistine coastal cities: Ashdod, Ashkelon, Gaza, Ekron). They had also relied on Egyptian help. The triple reliance: 'relied on' (mavtachenu), 'fled for help' (nasa leshavar, where we fled for help), and 'rescue from the king of Assyria' (lehinnatseil mippanei melech Ashshur, to be rescued from before the king of Assyria). All three expectations are shattered. 'How then shall we escape?' (ve'anachnu eikh nimmalet, and we — how will we escape?) — the rhetorical question that has no human answer. Only YHWH can provide escape (cf. 20's subtext: trust YHWH alone).</p>"
  },
  "21": {
    "1": "<p>Isaiah 21:1 opens the first of three oracles in this chapter: 'The oracle of the Desert of the Sea.' The 'Desert of the Sea' (massa midbar-hayam) is an unusual designation — no desert-sea exists. Most interpreters identify this as Babylon, approached from the desert to the east and surrounded by the marshy Tigris-Euphrates flood plain (called a 'sea' in Babylonian texts). The opening image: 'Like whirlwinds sweeping through the Negeb, it comes from the desert, from a dreadful land' — the sirocco whirlwinds (suphoth, whirlwinds/storm-winds) that sweep through the Negev with devastating speed and heat. The oracle comes from a 'dreadful land' (erets nora'ah, a fearful/terrible land) — Babylon is both the source of terror and the target of divine judgment.</p>",
    "2": "<p>'A grim vision has been shown to me: the traitor betrays, the plunderer plunders. March, O Elam! Besiege, O Media! All the groaning Babylon caused I will bring to an end' — the vision's content: 'marchasheh badoghed boged, vehashoded shed, a hard vision is shown to me; the treacherous dealer deals treacherously, and the plunderer plunders.' The poetic structure: two pairs of repeating root words (boged/badoghed; shoded/shed) emphasize the self-fulfilling nature of violence. 'March, O Elam! Besiege, O Media!' (ali Eilam, tsuri Madai, go up O Elam, lay siege O Media) — Elam (the region of southwestern Persia, Khuzestan) and Media (the Median empire of northwestern Iran) are explicitly named as the conquerors of Babylon. The historical fulfillment: Cyrus the Great combined Persian and Median forces to conquer Babylon in October 539 BCE.</p>",
    "3": "<p>'Therefore my body is racked with anguish; labor pains have seized me like those of a woman giving birth; I am too shaken to hear, too shattered to see' — the prophet's extraordinary personal anguish at the vision. 'Al-ken maleu chaluim motnai, therefore my loins are filled with anguish' (chaluim, writhing/pain). 'Tziroth achazatuni ketziroth yoledet, labor pains have seized me like the pains of a woman giving birth.' The prophetic anguish over the fall of Babylon is not triumphalism but genuine suffering — the prophet identifies with the victims even when the perpetrator-city deserves judgment. 'I am too disturbed to hear, too dismayed to see' (naaweiti mishome'a nivchalti mirroth, I was bent from hearing, I was terrified from seeing) — the vision is too overwhelming for normal prophetic reception.</p>",
    "4": "<p>'My mind reels; a shuddering terror grips me; the evening I had longed for has been turned into dread' — continued personal agony: 'ta'ah levavi, my heart staggers/is bewildered' (ta'ah, to stray/wander = the heart losing its orientation). 'A shuddering terror has seized me' (balahah biathatni, a shuddering/appalling thing terrifies me). 'The evening I had longed for has been turned into dread' (neshef chesheqti sam li lacharedah, the twilight I desired has been turned for me into trembling). The 'evening I had longed for' may refer to the watchman's hope for the morning (v.8) or to the banquet scene of v.5 — the festive evening of Belshazzar's feast (Dan 5) turned into sudden terror. The prophetic experience is not detached observation but visceral identification.</p>",
    "5": "<p>'Set the table, spread the rugs, eat and drink! Rise up, O princes, and oil the shields' — the festive scene interrupted by military alarm. The commands: 'aroch hashulchan, spread/set the table; tsafo hatsephiyyah, watch/lay out the watch; achal shato, eat, drink.' This is the banquet scene — Belshazzar's feast in Dan 5 describes exactly this: Babylon's rulers eating and drinking from the vessels of YHWH's temple when the writing on the wall appears. The sudden interruption: 'qumu hasarim mushu magen, rise O princes, oil/anoint the shields!' — the military command to prepare for battle (anointing shields with oil kept the leather supple for combat). The transition from festive table to military alarm is the moment Babylon's doom arrives.</p>",
    "6": "<p>'For this is what the Lord said to me: Go, station a watchman; let him report what he sees' — the watchman commission: 'lekh amod hatsopeh asher yir'eh yagid, go, station the watcher; what he sees let him declare.' The prophet is commanded to post a sentinel (tsopeh, the watchman/lookout) on the city wall or watchtower. The watchman motif is developed most fully in Ezekiel (Ezek 3:17; 33:1-9: 'Son of man, I have made you a watchman for Israel') where the prophet is made the community's sentinel responsible for warning of approaching danger. The 'what he sees let him report' = the watchman's function is to observe and faithfully transmit — accurate reporting without embellishment or suppression.</p>",
    "7": "<p>'The watchman saw a column of cavalry — riders in pairs, a caravan of donkeys, a caravan of camels — and he listened intently, with close attention' — the watchman's observation: a large military force approaching, described as cavalry in pairs (rekev tsemed parashim, a chariot/pair of horsemen), donkey caravan (chamor), camel caravan (gamal). The mixed cavalry-and-transport force suggests both the military strike force and the supply train of the invading army. 'He listened intently with close attention' (vayiqqeshev qeshev rabbah, and he listened with great attention) — the watchman is completely alert, every sense focused. The combination of sight (saw the column) and hearing (listened intently) describes total watchman vigilance.</p>",
    "8": "<p>'Then the lookout called out: My lord, I stand on the watchtower continually by day, and I keep my post every night' — the watchman's report of his own faithfulness: 'anokhi omed al-hammitzpeh tamid yomam, I stand on the watchtower continually by day, ve'al mishmarti anokhi nitsav kol-halayelot, and at my guard post I station myself all the nights.' The watchman is not asleep at his post — he has maintained continuous vigilance. This self-report establishes the credibility of what follows: when the watchman reports, he speaks from exhaustive, unbroken observation. Habakkuk 2:1 uses the same language: 'I will stand at my watch and station myself on the ramparts; I will look to see what he will say to me.'</p>",
    "9": "<p>'Here comes a column of men, horsemen in pairs! Then the watcher answered: Fallen, fallen is Babylon! All the carved images of her gods are shattered to the ground!' — the watchman's climactic report: 'nafala nafala bavel, fallen, fallen is Babylon!' The doubled verb (nafala nafala, fallen-fallen) is the emphatic completion — total, irreversible fall. 'All the carved images of her gods he has shattered to the ground' (vekhol-psilei eloheiha shibar la'arets, and all the carved images of her gods he has broken to the ground). The specific destruction of Babylon's divine images is both historical (Cyrus's forces would have dismantled the cult objects) and theological (the idols that 13:2 said would be shattered are shattered). Revelation 14:8 quotes this directly: 'Fallen! Fallen is Babylon the Great!' Rev 18:2 expands it for the eschatological Babylon.</p>",
    "10": "<p>'O my people, crushed and winnowed — what I have heard from the LORD of hosts, the God of Israel, I now declare to you' — the pastoral address to the exiles: 'Crushing and son of my threshing floor' (midushati uvenmad-goren, my crushed one and son of my threshing floor) — the exiles described as grain that has been crushed and winnowed, subjected to the threshing of exile. The 'my people' address (the prophet addressing the exiles as YHWH's) reestablishes the covenant relationship even in the context of judgment. What the prophet received as a grim vision (v.2) he now declares for the exiles' benefit: 'what I have heard from YHWH of hosts, the God of Israel, I have declared to you.' The oracle of Babylon's fall is good news for those under Babylon's power.</p>",
    "11": "<p>'The oracle of Dumah. A voice calls to me from Seir: Watchman, what is left of the night? Watchman, what is left of the night?' — the Dumah/Edom oracle: the shortest of Isaiah's burden oracles. 'Dumah' (dumah = silence/stillness) is likely a wordplay on 'Edom' (edom, the nation south of the Dead Sea, traditionally descended from Esau). Seir (the mountain range = Edom's territory, Gen 36:8-9). The voice calling from Seir: 'shomer meh-milleil shomer meh-milleil, watchman, what of the night? watchman, what of the night?' The double question creates urgency: the Edomites are in darkness and desperately want to know if morning (relief) is coming. The 'night' is both literal and metaphorical — the darkness of their situation under Assyrian pressure and the theological darkness of not knowing YHWH's purpose.</p>",
    "12": "<p>'The watchman said, Morning is coming, but so is the night. If you would inquire, inquire; come back again' — the watchman's cryptic response: 'ata boqer vegam-layelah, morning comes and also night.' Both morning (relief/salvation) and night (further darkness/judgment) are coming — the answer is deliberately ambiguous. The watchman is not refusing to answer but giving an honest, nuanced answer: some morning is coming, but more night follows. The closing invitation: 'im-tivayun bayu, if you will inquire, inquire; return, come.' Return (shuv, turn/repent — the covenant vocabulary) and come. The oracle offers conditional openness: if Edom turns (to YHWH?), the conversation can continue. The ambiguity of the Edom oracle reflects the ambiguity of Edom's covenantal status — related to Israel (Esau-Jacob) but outside the covenant.</p>",
    "13": "<p>'The oracle concerning Arabia. You caravans of the Dedanites, take shelter in the thickets of Arabia' — the Arabia oracle: Dedan (modern al-Ula/Mada'in Saleh in northwestern Saudi Arabia, a major North Arabian trading center on the incense route) is commanded to take shelter (linu, lodge/spend the night) in the thickets/forest of Arabia (bya'ar ba'arav, in the thicket of Arabia). The Arabic 'Arabia' (arav = wilderness/steppe) is both a geographic designation and a description of the terrain. Dedan was a major waystation on the incense route from South Arabia (Yemen) to the Mediterranean. The Dedanite caravans that normally passed through openly are now sheltering in brush cover — fleeing military threat.</p>",
    "14": "<p>'Bring water to the thirsty, O people of Tema; go out with food to meet the fugitives' — Tema (modern Tayma, an oasis city in northwestern Saudi Arabia, mentioned in Nabataean and Neo-Babylonian inscriptions — Nabonidus, the last Babylonian king, actually resided in Tema for ten years) is called to bring water (mayim, water) to the thirsty (tzame, the thirsty ones) and 'with food they went out to meet the fugitives' (belihem qidmu noddedim, with their food they went out to meet the wandering refugees). The humanitarian action — providing water and food to fleeing refugees — is commanded in the context of the military rout. The Arabian tribes who normally traded peacefully are now hosting war-refugees.</p>",
    "15": "<p>'For they have fled from the swords, from the drawn sword, from the bent bow, and from the fury of battle' — the triple instrument of flight: 'mi-penei cheravot nasu, from before the swords they fled' — mepenei cherev hantuyyah (from before the outstretched/drawn sword), umepenei qeshet derukhah (from before the bent/strung bow), umepenei kovad milchamah (from before the heaviness/fury of battle). The three weapons and the 'fury of battle' specify the military context — this is not natural disaster or famine but military campaign. The Assyrian campaigns into Arabia (particularly Esarhaddon and Ashurbanipal who campaigned against Arab tribes) are the historical background for Arabia's destabilization.</p>",
    "16": "<p>'For this is what the Lord said to me: Within a year, reckoned as a hired worker counts a year, all the wealth of Kedar will come to nothing' — Kedar (the dominant North Arabian tribal confederation, associated with the descendants of Ishmael, Gen 25:13; mentioned in Assyrian records as Qidri) will be destroyed 'within a year' (od shanah kishne sakir, within a year as the years of a hired worker — the same precise time formula as 16:14 for Moab, indicating exactly one contractual year). 'All the wealth of Kedar will come to nothing' (kol kevod Qedar, all the glory/wealth of Kedar). Kedar was famous for its herds (Ps 120:5; Song 1:5; Isa 60:7 mentions Kedar's rams as tribute), its archers (Isa 21:17), and its trading capacity.</p>",
    "17": "<p>'The remaining archers — the warriors of Kedar — will be greatly diminished, for the LORD, the God of Israel, has spoken' — the remnant of Kedar's warriors reduced: 'veshe'ar mispar qeshet gibborei benei Qedar yim'atu, and the remnant of the number of bows of the mighty warriors of the sons of Kedar will be few.' Kedar's military identity was its archers — the Arabian bow warriors were renowned in the ANE. The diminishment of the bows = the diminishment of Kedar's military capacity. The closing authorization: 'ki YHWH Elohei Yisrael dibber, for YHWH the God of Israel has spoken' — the God of Israel speaks the fate of Arabia. YHWH as God of Israel is sovereign over the Arabian desert tribes who had no connection to the Sinai covenant.</p>"
  },
  "22": {
    "1": "<p>Isaiah 22:1 opens the most unexpected of the burden oracles: a judgment on Jerusalem itself. 'The burden of the Valley of Vision' (massa gei hazon, the oracle of the valley of vision) — Jerusalem is the 'Valley of Vision,' the place where prophetic visions are received (perhaps the Hinnom Valley, the Kidron Valley, or the temple precinct where prophets stood). The irony: Jerusalem, YHWH's holy city, now receives a burden/judgment oracle like the pagan nations. 'What has come over you that you have all climbed up to the housetops?' (mah-lach ki alita kullech legagot, what is with you that all of you have gone up to the housetops?) — the rooftops were used for watching, signaling, and public celebration (cf. the Feast of Tabernacles sukkot built on rooftops, Neh 8:16). The people are celebrating, but the celebration is inappropriate.</p>",
    "2": "<p>'You are a city full of uproar and celebration! But your slain were not killed by the sword, and your dead did not fall in battle' — the celebration in the city is hollow: 'hamoniyah ir-homiyah, a tumultuous city, a joyous city' (the double noun emphasizing the noise and festivity). But the deaths in Jerusalem were not heroic military deaths: 'chalalachayich lo chalalei cherev, your slain are not those slain by the sword' and 'umeteich lo metei milchamah, and your dead are not fallen of battle.' This suggests the specific historical referent is the 701 BCE Sennacherib siege aftermath: the city survived not through military heroism but because YHWH struck the Assyrian army (2 Kgs 19:35). The people celebrating their 'victory' are actually celebrating their fear-based survival, not genuine triumph.</p>",
    "3": "<p>'All your commanders fled together; they were captured without a bow being drawn; all who were found among you were taken prisoner, even those who had fled far away' — the military failure described: 'kol-qetsineich nadedu yachdav, all your chiefs fled together, they were captured without a bow (miqkeshet nusaru, without bow they were captured).' The commanders who should have led the defense fled together — taken prisoner (neshbu) without even the dignity of military resistance. 'All who were found among you were taken prisoner, together with those who had fled far away' (kol asher nimetsa bakh nishbu yachdav, all who were found in you were captured together) — both those in the city and those who tried to escape. The military collapse is complete: no heroic resistance, no honorable surrender, just flight and capture.</p>",
    "4": "<p>'Therefore I said, Turn away from me; let me weep bitterly; do not try to comfort me over the ruin of the daughter of my people' — the prophet's grief over Jerusalem: 'al-ken amarti she'u mimenni, therefore I said: Look away from me; I will weep bitterly.' Isaiah refuses comfort (al-te'itsu lenachameni, do not try to comfort me/urge me to be comforted) over 'the ruin of the daughter of my people' (al-shod bat-ammi, over the destruction of the daughter of my people). The 'daughter of my people' (bat-ammi) is a tender designation for Jerusalem/the covenant community as a vulnerable woman (cf. Lam 1:15; 2:11; 3:48; Jer 8:21 — 'I am broken over the brokenness of my people'). The prophet's grief anticipates Jeremiah's more extended lamentations over Jerusalem's fall.</p>",
    "5": "<p>'For the Lord GOD of hosts has a day of panic and trampling and confusion in the Valley of Vision — walls crashing down, a war-cry echoing off the mountains' — the Day of the LORD applied to Jerusalem: 'yom mehuma umevusah umevukhah laAdonay YHWH tseva'ot begei hazon, a day of panic and trampling and confusion for the Lord YHWH of hosts in the Valley of Vision.' The three nouns of chaos: mehuma (panic/tumult), mevusah (trampling), mevukhah (confusion). 'Qir meqarqar vesha'a el-hahar, the wall is breaking down and crying out to the mountain' — the fortification wall collapsing and the war-cry (she'ah, clamor/thunder) echoing off the surrounding mountains. The 'Valley of Vision' as a site of YHWH's judgment echoes Joel 3:2, 12 (the Valley of Jehoshaphat where YHWH judges all nations — now applied to Jerusalem itself).</p>",
    "6": "<p>'Elam took up the quiver with chariots and cavalry, and Kir bared the shield' — the specific military forces attacking Jerusalem: Elam (the kingdom of southwestern Persia, Elamite troops serving in the Assyrian army under Sennacherib) and Kir (possibly a Mesopotamian region — 2 Kgs 16:9 says Tiglath-Pileser III deported Arameans to Kir; Amos 9:7 mentions Kir as Syria's origin). 'Elam bore the quiver' (nasa Eilam ashpah, Elam carried the quiver) with chariots and cavalry (brekev adam parashim, with the chariot of men, with horsemen). 'Kir uncovered the shield' (Qir gillah magen, Kir uncovered the shield) — preparing for battle by removing the shield's leather cover. The specific Elamite and Kir forces are a detail that suggests an 8th-century composition (before Persia's rise as a major power).</p>",
    "7": "<p>'Your finest valleys were choked with chariots, and cavalry were posted at the city gates' — the siege deployment: 'vayehi mivchar ameqayikh male harekev, and it came to pass that the choice/finest of your valleys was filled with chariots' and 'uhaparashim shoth shatu hasha'arah, and the horsemen positioned themselves/posted at the gate.' The valleys surrounding Jerusalem (Kidron, Tyropoeon, Hinnom) filled with Assyrian chariot forces. The city gates (hasha'arah) blocked by cavalry — the standard siege perimeter preventing escape or resupply. Sennacherib's 701 BCE siege of Jerusalem is described in 2 Kgs 18:17 as involving an Assyrian field commander, chief officer, and field commander with a large army.</p>",
    "8": "<p>'He stripped away Judah's defenses. On that day you turned to the arsenal stored in the House of the Forest' — 'vayekhes et-masakh Yehudah, and he removed the covering of Judah' — the 'covering' (masakh, the screen/veil) = the defensive system that protected Judah. YHWH (or the Assyrian king) removes this protection. 'You looked to the arsenal of the House of the Forest' (vatabet el-nesheq beit haya'ar, and you looked to the weapons of the House of the Forest) — the House of the Forest of Lebanon was Solomon's cedar-paneled armory in Jerusalem (1 Kgs 7:2-5; 10:16-17). It was the central weapons depot where 500 golden shields were stored. The first response to the siege: reaching for human military resources rather than divine help.</p>",
    "9": "<p>'You saw that the gaps in the wall of the city of David were numerous, and you collected water into the lower pool' — the specific emergency preparations: 'uretsioth ir David ki rabu, and the breaches of the City of David because they were many.' The 'City of David' is the ancient fortified core of Jerusalem on the eastern hill (the original Jebusite city David captured). The water preparation: 'vatiqabetsu et-mei habitrechah hatachtona, and you collected the water of the lower pool.' The 'lower pool' was probably the Pool of Siloam at the base of the City of David, supplied by Hezekiah's famous tunnel (2 Kgs 20:20; 2 Chr 32:3-4). The Siloam Tunnel inscription (discovered 1880) documents the actual tunneling work, confirming Hezekiah's emergency water preparations before the Assyrian siege.</p>",
    "10": "<p>'You took inventory of Jerusalem's houses and demolished buildings to strengthen the wall' — the military engineering of the siege preparation: 'usefartem et-batei Yerushalayim, and you counted/numbered the houses of Jerusalem' — conducting a census of buildings available for materials. 'Vatitsu habatim litsbots hachomah, and you demolished houses to strengthen the wall' — tearing down structures to use their stone to repair and strengthen the city wall. This was standard siege-preparation practice: strengthening the defenses by any available means. 2 Chr 32:5 describes Hezekiah's wall preparations: 'He worked hard repairing all the broken sections of the wall and building towers on it, and also building another wall outside it.' The archaeological evidence (the 'Broad Wall' excavated by Avigad in the Jewish Quarter of Jerusalem) confirms Hezekiah's 8th-century wall extension.</p>",
    "11": "<p>'You built a cistern between the two walls to hold the water of the old pool, but you did not look to the one who made all this possible, nor did you give thought to the one who planned it long ago' — the great failure: all the engineering preparations without theological consultation. The cistern between the two walls (mikveh asitem bein hachomotayim, a reservoir you made between the two walls) for the water of 'the old pool' (habereikhah hayshanah, the old pool). All this technical brilliance — water tunneling, wall building, arsenal management, water collection — but 'lo habitem el-oseha, you did not look to its maker' (the one who made both the city and its resources) 'and la'oseh lo ra'item, to its fashioner you did not look' (the one who fashioned/planned it long ago). The engineers consulted the engineering but not the engineer of all creation.</p>",
    "12": "<p>'In that day the Lord GOD of hosts called for weeping and mourning, for shaving the head and putting on sackcloth' — the appropriate response to the Day of the LORD: YHWH himself summoned (vayiqra adonay YHWH tseva'ot, and the Lord YHWH of hosts called). The four mourning acts: 'livki ulemisped, to weeping and mourning; ulqorchah vekhaghor saq, to shaving the head and wearing sackcloth.' These four are the complete mourning repertoire (shaving = Isa 15:2; Job 1:20; sackcloth = 2 Sam 3:31; Neh 9:1; mourning = Jer 9:17-18). YHWH's call to mourning is the recognition that this situation requires genuine grief and repentance — not the defensive preparations of vv.8-11, but humiliation before God. Judah's response to the call to mourning is the exact opposite of what was required.</p>",
    "13": "<p>'But instead there was only celebration — slaughtering oxen, killing sheep, eating meat and drinking wine: Let us eat and drink, for tomorrow we die!' — the defiant festivity: 'vehineh sason vesimchah, and behold — joy and gladness.' The specifics of the celebration: 'harog bakar veshochet tso'n, slaughtering cattle and killing sheep' (the festive meals of abundance), 'akhol basar veshato yayin, eating meat and drinking wine.' The slogan: 'akhol veshato ki machar namut, let us eat and drink for tomorrow we die!' This Epicurean philosophy of crisis — live for the moment because death is coming — is the exact inversion of YHWH's call to mourning. Paul quotes this slogan in 1 Cor 15:32: 'If the dead are not raised, \"Let us eat and drink, for tomorrow we die\"' — Paul inverts it: because the dead ARE raised, this slogan is wrong.</p>",
    "14": "<p>'The LORD of hosts revealed this directly in my hearing: This guilt will never be atoned for while you live, says the Lord GOD of hosts' — the irrevocable judgment: 'veNiglah be'ozanei YHWH tseva'ot, and it was revealed in my ears by YHWH of hosts.' The direct divine revelation 'in my ears' emphasizes intimacy and certainty — this is not second-hand oracle but direct communication. 'Im-yekuppar ha'avon hazeh lakhem ad tmutem, this iniquity will not be atoned for you until you die.' The guilt (avon, the specific moral crookedness of celebrating during judgment) cannot be atoned for (yekuppar, covered/atoned — the kippurim/atonement vocabulary) as long as they live. The seriousness: the festivity of vv.12-13 is not merely impious but seals the community's judgment. The 'says the Lord GOD of hosts' closure is the divine authentication of the permanence of the verdict.</p>",
    "15": "<p>'This is what the Lord GOD of hosts says: Go to this steward, this Shebna who is in charge of the palace' — the transition to the personal oracle against Shebna: 'koh amar adonay YHWH tseva'ot lekh bo el-hasoken hazeh al-shevna asher al-habayit, thus says the Lord YHWH of hosts: Go to this steward, this Shebna who is over the house.' The soken (steward/administrator) is the palace administrator, the highest civilian official in the royal court. 'Asher al-habayit' (who is over the house) = the palace chamberlain, second only to the king. 2 Kgs 18:18, 26; 19:2 confirms Eliakim ben-Hilkiah as the man 'over the house' during the Assyrian siege — Shebna had been demoted to 'secretary/scribe' (sofer), fulfilling the oracle's prediction of removal from the top position.</p>",
    "16": "<p>'What gives you the right to be here? Who do you think you are, carving yourself a tomb here on the heights — hewing a burial chamber for yourself in the rock?' — the prophetic accusation against Shebna's tomb-building: 'mah-lecha foh umi-lecha poh, what have you here and who have you here?' — the double 'what and who' challenges Shebna's entitlement to this prominent burial site. 'Ki chatsavta lecha po qever, that you have cut/hewn for yourself here a tomb' — hewing (chatsav, cutting stone) a rock-cut tomb 'on the heights' (bammarom, in the high place). The rock-cut tombs of Jerusalem's wealthy are attested archaeologically — the Garden Tomb, the Tombs of the Kings, and multiple Iron Age tomb complexes show the elite carving elaborate burial chambers in the rock escarpment. An inscription discovered in Silwan in 1870 reads: 'This is the tomb of [YHWH]yahu who is over the house' — possibly Shebna's own tomb inscription.</p>",
    "17": "<p>'See — the LORD is about to hurl you away with a violent throw, O man; he will take hold of you and fling you far' — the judgment on Shebna using the image of athletic throwing: 'hineh YHWH metaltlekhah talteilah, behold YHWH will hurl you with a great hurling' (the intensifying repetition: tilteil from the root meaning to throw with a swinging motion). 'Gever ve'atah' (O man, and you — the 'mere man!' mockery from 14:16 applied now to Shebna). 'He will seize you firmly' (ota ateh viltah, he will grasp you with grasping). The image of YHWH physically throwing Shebna like a stone (the sling-stone analogy of v.18) applies the ancient power-metaphor of divine hurling to the proud official who built his tomb 'on the heights.'</p>",
    "18": "<p>'He will ball you up and fling you like a stone across a wide open land; there you will die and your splendid chariots will lie there — you, the shame of your master's household!' — the hurling completed: 'tsanof yitsanefkha tsenefah kaddur, he will certainly roll you into a ball and hurl you like a ball' (tsanaf = to wrap/roll, creating the image of rolling Shebna up like a ball). 'Into a wide country' (el-erets rachavat yadayim, into a land wide of hands = a broad country) — exile to a far land. 'There you will die and there your splendid chariots will be' (sham tamut vesham yihyu markevoth kevodekhah, there you will die and there will be the chariots of your glory). The chariots that were Shebna's pride and symbol of status will be left in the foreign exile. 'The shame of your master's household' (qalon beit adoneykhah, the disgrace of your master's house) — the official who should honor his master has become his disgrace.</p>",
    "19": "<p>'I will remove you from your position, and you will be pulled down from your office' — the official demotion: 'vehadeftikhah mimmatstzevat-ekha, and I will shove you from your post' (dafah, push/shove). 'Umimmatstzavtkhah yeharekhah, and from your station he will pull you down.' The 'post' (matstzevat, standing position = official post/station) and 'station' (matstzavah, standing place = position of authority) are the technical terms for a court official's assigned position. The oracle is fulfilled in 2 Kgs 18:18 where Eliakim is 'over the house' during the Sennacherib crisis and Shebna is reduced to 'scribe/secretary' — exactly the demotion from the top administrative position to a secondary role that the oracle predicts.</p>",
    "20": "<p>'In that day I will summon my servant Eliakim son of Hilkiah' — the replacement official: 'vehayah bayom hahu eqra leabdi leElyakim ben-chilqiyyahu, and it will be in that day that I will call to my servant, to Eliakim son of Hilkiah.' Eliakim (el-yakim, God will establish/raise up) is YHWH's 'servant' (eved) — the same title as Isaiah (20:3: 'my servant Isaiah') and the Servant of the Songs (42:1; 49:3; 52:13; 53:11). The title 'servant of YHWH' is the highest honorific in prophetic theology. 2 Kgs 18:18 confirms Eliakim son of Hilkiah as 'who was in charge of the palace' during the Assyrian siege — the historical figure named in this oracle appears in the narrative of 701 BCE.</p>",
    "21": "<p>'And I will dress him in your robe and fasten your sash around him; I will hand your authority over to him, and he will be a father to the people of Jerusalem and to the house of Judah' — the investiture of Eliakim with Shebna's office: 'vehalbashetiv kuttantekha veme'il avnetkhah achazeq bo, and I will clothe him with your tunic and your sash I will bind firmly on him.' The robe and sash are the symbols of court office — the investiture garment and the characteristic belt of the palace administrator. 'Memshaltekhah ve'ettiyan beyado, your authority/governance I will give into his hand' — the complete transfer of official power. But the key quality: 'vehayah le'av leyoshev Yerushalayim uleveit Yehudah, and he will be a father to the inhabitants of Jerusalem and to the house of Judah.' The good official serves as a father, not a proud self-seeker like Shebna.</p>",
    "22": "<p>'I will lay on his shoulder the key of the house of David; what he opens no one will shut, and what he shuts no one will open' — the key of David: 'venatatti maftach beit-David al-shekhmo, and I will put the key of the house of David on his shoulder.' The key to the king's palace was literally carried on the shoulder by the palace steward — a large, heavy iron key (the keys of ancient Near Eastern palaces were substantial objects). As the steward with the key, Eliakim controls access to the king: 'upatach ve'ein soger, and he will open and none will shut; usagar ve'ein poteach, and he will shut and none will open.' The absolute authority of the gatekeeping role. Revelation 3:7 applies this directly to Jesus ('what he opens no one can shut, and what he shuts no one can open') — the messianic palace-steward whose authority is eternal and universal.</p>",
    "23": "<p>'I will drive him in like a peg into a solid place, and he will become a throne of glory to his ancestral household' — the peg image: 'vetiqativi yated bemaqom ne'eman, and I will drive him as a peg into a sure/established place' (yated, a tent-peg or wall-peg; maqom ne'eman, a firm/established place). The peg driven firmly into solid ground/wall is an image of stable authority — the official who can support the weight hung on him. 'Vehayah lekise kavod leveit aviv, and he will be as a throne of glory to the house of his father' — the official becomes the 'throne of glory' (kise kavod = seat of honor) for his ancestral household. The imagery of the reliable peg carrying others' honor will be inverted in v.25.</p>",
    "24": "<p>'They will hang on him all the honour of his father's household — descendants and offshoots, every vessel from the smallest cup to every jar' — the weight of dependents hung on Eliakim's authority: 'vetalu alav kol kevod beit aviv, and they will hang on him all the glory of his father's house.' The dependents: 'hatsa'etsaim vehatsephiot, the descendants and the twigs/offshoots' (tsa'etsaim = children/branches; tsephiot = runners/offshoots = junior family members). The vessel imagery: 'kol kelei haqaton min-haagganot ad kol-kelei hanevalim, every vessel of the small ones, from the cups to every jar/flask.' The great variety of vessels (cups = small; jars/nevalim = large storage vessels) hung on the reliable peg of the official's authority represents the full economic and social dependence of many people on one reliable official.</p>",
    "25": "<p>'In that day, declares the LORD of hosts, the peg that was driven into the solid place will fail; it will be cut down and fall, and the weight hanging on it will be severed — for the LORD has spoken' — the shocking conclusion: even Eliakim the good official will eventually fail. 'Tamus hayated hatequah bemaqom ne'eman, the peg driven into the solid place will give way' — the same peg described as firmly driven in v.23 now gives way (tamus, will loosen/give way). 'Veniqtza unaflah, and it will be cut off and fall; and the weight that hangs on it will be severed/cut' (venickrath hamasa asher aleha). All human authority is temporary — even the most reliable official will be removed or die. Only the divine palace steward (Rev 3:7: Jesus who holds the key of David) never fails. The oracle's ending with the failure of even Eliakim points beyond all human administrators to the one whose key-holding is permanent.</p>"
  },
  "23": {
    "1": "<p>Isaiah 23 is the final and culminating burden oracle of chs. 13-23: the burden of Tyre (massa Tsor). Tyre was the greatest maritime trading city of the ancient world — a Phoenician city-state on a small island off the modern Lebanese coast (later connected to the mainland by Alexander the Great's causeway, built during his famous 7-month siege of 332 BCE). 'Wail, ships of Tarshish' (yeliloo oniyot tarshish, wail O ships of Tarshish) — Tarshish (probably Tartessos in Spain or Sardinia) was the western terminus of Phoenician trade. The ships of Tarshish were the largest ocean-going vessels of the ancient world (1 Kgs 10:22: Solomon's Tarshish fleet brought gold, silver, ivory, apes, and baboons). The news comes from Cyprus (Kittim, the island of Cyprus, where Tyre had important colonies and commercial interests) — Tyre is destroyed.</p>",
    "2": "<p>'Be still, you people of the coastland — you whom Sidon's merchants, who sailed the seas, once made wealthy' — the silence of shock: 'domu yoshevei iy, be silent O inhabitants of the coastland' (domu = be still/silent in stunned grief). Sidon (Tyre's sister city, the older of the two great Phoenician ports, 35 miles north of Tyre on the Lebanese coast) is here associated with Tyre in the trading network. 'Whom the merchants of Sidon, who cross the sea, have made wealthy' (asher socharei Tsidon oberai yam milu'ach, whom the merchants of Sidon who pass over the sea have filled) — the whole coastland's prosperity was built on Phoenician maritime trade. Sidon's own role in the oracle is that of a partner who must mourn Tyre's fall.</p>",
    "3": "<p>'The grain of Shihor — the harvest of the Nile — crossed the great waters and became her income; she was the market town of nations' — the grain trade through Tyre: 'beme'um may, veqatsir yeor tevu'atah, and on great waters the seed of Shihor, the harvest of the Nile, was her revenue.' Shihor (shichor, the turbid one) = the Nile delta branch, or the Wadi el-Arish (the brook of Egypt) — the Egyptian grain supply. Tyre was the broker (sochar goyim, merchant/marketplace of nations) that connected Egypt's agricultural surplus to the Mediterranean world's consumption needs. The grain trade from Egypt through Phoenician shipping to the Mediterranean world is historically documented — Tyre was the critical middleman in one of the ancient world's most important commodity flows.</p>",
    "4": "<p>'Be ashamed, O Sidon, for the sea has spoken — the sea's own fortress declares: I have not travailed or given birth; I have raised no young men and nurtured no young women' — Sidon called to shame: 'boshi Tsidon ki amar yam, be ashamed O Sidon for the sea has said' — the sea itself speaks as a witness. 'Ma'oz hayam, the strength/fortress of the sea' (the sea-fortress = Tyre on its island) says: 'lo chalti velo yiladeti, I have not travailed and I have not given birth; lo gidaleti bahurim, lo rommamti betulot, I have not raised up young men, I have not brought up young women.' The sea-fortress Tyre speaks as a barren mother — the city that should be teeming with life (the young men and women of a flourishing maritime population) declares itself childless. The barrenness metaphor = the cessation of Tyre's commercial generation of wealth and people.</p>",
    "5": "<p>'When the news reaches Egypt, they will writhe with anguish at what has happened to Tyre' — the global reaction to Tyre's fall: 'ka'asher shema lemitsrayim, as when the news is heard in Egypt.' Egypt will writhe (yachilu, will writhe with labor pains = the same labor-pain anguish of 13:8 and 21:3 for the nations at the Day of the LORD) 'at the news of Tyre' (keshama Tsor, when the news about Tyre is heard). Egypt's dependence on Tyre as the broker of Mediterranean trade means that Tyre's fall directly impacts Egypt's economic interests. The pain of Egypt is the pain of a trade partner losing its essential network.</p>",
    "6": "<p>'Sail across to Tarshish! Wail, you people of the coastland!' — the flight command: 'ivru Tarshish, cross over to Tarshish!' — the Phoenician refugees are directed to flee to their western colonial outpost in Spain/Sardinia. 'Heliilu yoshevei iy, wail O inhabitants of the coastland!' — the coastland (the Phoenician coast and its island colonies) called to lament. The irony: Tarshish, which represented the farthest extension of Phoenician commercial power, is now the refuge for Phoenician refugees. The network of commerce becomes the network of escape routes.</p>",
    "7": "<p>'Is this the city that you once celebrated — so ancient in its origins, a city whose people sailed out to settle far-off shores?' — the rhetorical question about Tyre's identity: 'hazot lakhem alizah, is this to you your exultant/joyful city?' The 'exultant city' (alizah, rejoicing/jubilant) reduced to ruin. 'Asher qadmatah le'olam, whose origin is from ancient time' — Tyre claimed enormous antiquity. Herodotus (2.44) records that the Tyrian priests told him the Heracles temple was 2300 years old — placing Tyre's founding around 2750 BCE. 'Takalineha ragleyha merachok lagur, her feet carried her far away to sojourn' — the Phoenicians' colonization: Carthage (814 BCE), Cyprus, Sicily, Sardinia, Spain — 'far-off shores' settled by Tyrian commercial outposts.</p>",
    "8": "<p>'Who planned this against Tyre — the crown-bestowing city, whose traders were princes, whose merchants were among the most celebrated people on earth?' — the rhetorical question about the architect of Tyre's fall: 'mi ya'atz zot al-Tsor ha'atarah, who planned this against Tyre the crowning one?' Tyre as 'the crown-bestowing' (ha'atarah, the one who gives crowns) — Tyre's commercial power enabled it to raise cities to power (planting colonies, establishing trading posts). 'Asher sochareiha sarim, kena'aneiha nikbaddei-erets, whose merchants are princes, whose Canaanites are among the honored of the earth' — the merchants of Tyre hold princely status, and even the ordinary 'Canaanites' (traders — Canaan/Phoenicia being associated with trade to the point where 'Canaanite' became a synonym for 'merchant' in later Hebrew, Prov 31:24; Zech 14:21) are honored throughout the world.</p>",
    "9": "<p>'The LORD of hosts planned it — to strip the pride from all magnificence and to humiliate all the famous of the earth' — the divine answer to v.8's question: 'YHWH tseva'ot yaazhah, YHWH of hosts has planned it.' The purpose: 'lechalel ge'on kol-tzibi, to profane/strip the pride of all glory/splendor' and 'lehaqel kol-nikbaddei erets, to bring contempt on all the honored/famous of the earth.' The same two purposes as 2:11-12 (the Day of the LORD against everything proud and lofty): the Tyre oracle is the specific commercial-power instance of the universal Day-of-the-LORD pattern. YHWH's purpose in judging Tyre is not specific animosity toward Phoenicia but the universal judgment against human pride and the human claim to self-sufficiency.</p>",
    "10": "<p>'Flow through your land like the Nile, O daughter of Tarshish; there is nothing to hold you back any longer' — the liberation of Tarshish from Tyrian control: 'ivri artzekhemayior bat-tarshish, cross/flow through your land like the Nile, O daughter of Tarshish.' With Tyre destroyed, Tarshish (Tyre's western colony) is free: 'ein mozen od, there is no longer a belt/girdle' (mozen = girdle/control) restraining them. Tyre as a colonial power controlled the western Mediterranean trade routes and the daughter-cities' commerce. The liberation of Tarshish from Tyrian commercial hegemony = the freedom of the western Mediterranean from Phoenician dominance. The Nile-flow image suggests abundance flowing freely without restriction.</p>",
    "11": "<p>'The LORD stretched his hand out over the sea and shook the kingdoms; he has issued his order against Phoenicia to demolish its fortresses' — the divine warrior against the sea: 'YHWH natah yado al-hayam, YHWH stretched out his hand over the sea' — the theophanic gesture of cosmic power (the same 'outstretched hand' from the judgment-cycle of 9:12-10:4 and 14:26-27, now applied to the Mediterranean sea and Tyre's island). 'Hirgiz mamlekhot, he has shaken the kingdoms' — the kingdoms that depended on Tyre's trade network all shaken. 'YHWH commanded against Phoenicia (Canaan) to destroy its fortresses' — the divine decree against the Phoenician commercial network.</p>",
    "12": "<p>'He said, Your days of celebration are finished, O crushed virgin daughter of Sidon. Get up; cross to Cyprus — but even there you will have no rest' — the personified Sidon: 'yeamar lo tosifi od laalos, he said: you will no longer rejoice/celebrate' (the exultant commercial joy of v.7 ended). 'Ata anusah vatulat bat-Tsidon, O oppressed/crushed virgin daughter of Sidon' — Sidon personified as a young woman crushed by military force. The command to flee to Cyprus (Kittim, the closest Mediterranean refuge) is even denied: 'gam-sham lo-yanuach lakh, even there you will have no rest.' Rest (nuach, the resting of security) — the same word as YHWH giving rest from oppression (14:3) — is denied to Sidon in Cyprus. The entire network of Phoenician commercial refuge offers no escape from the divine judgment.</p>",
    "13": "<p>'Look at the land of the Chaldeans — a people who were nothing until Assyria raised them up; they erected siege towers against Tyre, stripped its palaces bare, and turned it to rubble' — the historical instrument of Tyre's judgment: the Chaldeans (Kasdim, the Babylonians under Nebuchadnezzar). 'Hinneh erets Kasdim zeh ha'am lo hayah, behold the land of the Chaldeans — this people was nothing.' The Chaldean rise to power is noted: 'Ashshur yissedah letziyyim, Assyria established/founded it for the jackals/desert-creatures' (or: 'Assyria raised them up') — the Chaldeans (southern Babylonian tribal confederacy) were a minor player until the Neo-Babylonian Empire of Nabopolassar (625-605 BCE) and Nebuchadnezzar II (605-562 BCE). Nebuchadnezzar's 13-year siege of Tyre (585-572 BCE) partially fulfilled this oracle, though Alexander's 332 BCE destruction was more complete.</p>",
    "14": "<p>'Wail, ships of Tarshish — your fortress harbour is destroyed!' — the inclusion: the oracle comes full circle from v.1's 'wail, ships of Tarshish' to this closing repetition. The ships of Tarshish called to wail at the opening and closing of the oracle — a literary frame. 'Yeliloo oniyot tarshish ki shudad ma'oz khem, wail O ships of Tarshish for your fortress is destroyed.' The 'fortress' (ma'oz, stronghold) = Tyre the island-fortress that protected and enabled the commercial network. Without the fortress-port of Tyre, the Tarshish ships have no safe harbor, no commercial center, no protection network.</p>",
    "15": "<p>'In that day Tyre will be forgotten for seventy years — the span of one king's lifetime. At the end of seventy years, Tyre will be treated like the woman in the prostitute's song' — the seventy-year framework: 'vehayah bayom hahu venishshechah Tsor shiv'im shanah kimei melech echad, and it will be in that day that Tyre will be forgotten seventy years like the days of one king.' The 'seventy years' is also the framework of the Babylonian exile (Jer 25:11-12; 29:10): 'the whole country will become a desolate wasteland, and these nations will serve the king of Babylon seventy years.' The parallel between Tyre's seventy-year eclipse and Judah's seventy-year exile suggests both are under the same divine governance of historical time. After seventy years: Tyre 'will be treated like the prostitute's song' (kehashirah hazzonah, like the song of the prostitute).</p>",
    "16": "<p>'Pick up your harp, walk the streets, O forgotten prostitute; play your sweetest tune and sing song after song so that someone might remember you' — the prostitute's song: 'kichi kinnor, sivi ir, zonah nishkachah, take a harp, go around the city, O forgotten prostitute!' The harp-carrying street-musician as a metaphor for Tyre's commercial re-engagement after eclipse: using cultural attractions to regain commercial partners. 'Heytivi naggein, harbi shir lema'an tizzakeri, play well, multiply your songs so that you will be remembered.' Tyre's commercial 'songs' = the commercial attractions (goods, services, trade relationships) that she uses to re-establish her network after seventy years. The prostitute metaphor for commercial trading ('selling herself to all the kingdoms') is extended in Ezek 27-28 (Tyre as the 'perfect beauty,' then the guilty merchant of the sanctuary).</p>",
    "17": "<p>'At the end of seventy years the LORD will attend to Tyre, and she will return to her trading — selling herself to all the kingdoms of the world' — the restoration after seventy years: 'vehayah miqets shiv'im shanah yipqod YHWH et-Tsor, and it will be at the end of seventy years that YHWH will attend to/visit Tyre.' The paqad (attend to/visit) is the covenant-activation verb — YHWH's visiting produces either judgment or restoration depending on context (Exod 3:16: YHWH visited Israel in Egypt; 2 Kgs 23:24 negative). Tyre's restoration: 'veshavah el-etnanah, and she will return to her prostitute's wages' (etnan, the wages of a prostitute — the commercial revenue of trading). 'Vezantah et-kol-mamlakhot ha'arets al-penei ha'adamah, and she will prostitute herself to all the kingdoms of the earth on the face of the ground' — universal commercial re-engagement.</p>",
    "18": "<p>'But her merchandise and her earnings will be set apart as holy to the LORD; they will not be stored up or hoarded, for her profit will supply those who live before the LORD with abundant food and quality clothing' — the eschatological consecration of Tyre's commercial wealth: 'vehayah socharah ve'etnanah qodesh laYHWH, and her merchandise and her wages will be holy to YHWH.' The ultimate transformation: Tyre's commercial revenues (the 'prostitute's wages' of v.17) become holy (qodesh, set apart for YHWH). 'It will not be stored up or hoarded' (lo ye'apher velo yechassen, not treasured and not stored as reserve) — the wealth will not be accumulated for Tyre's own power but immediately channeled: 'ki liyoshevim lifnei YHWH yihyeh sacharah, for those who dwell before YHWH will be her merchandise' — supplying the covenant community with 'abundant food and quality clothing.' The final vision: Tyre's commercial power consecrated to sustaining YHWH's people — the commercial economy redeemed and redirected to covenant purposes.</p>"
  }
}

def main():
    c = load_comm('mkt-context', 'isaiah')
    merge_comm(c, ISA_CONTEXT)
    save_comm('mkt-context', 'isaiah', c)
    total_v = sum(len(vv) for vv in c.values())
    print(f'Isaiah context: {len(c)} chapters, {total_v} verses')

if __name__ == '__main__':
    main()
